CREATE TRIGGER trigger_del_asset_location AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM asset_location where asset_id = old.asset_id; END;
CREATE TRIGGER trigger_del_bach_cluster_relation AFTER DELETE ON face FOR EACH ROW  BEGIN  DELETE FROM bach_cluster_relation where  face_id = old.face_id; END;
CREATE TRIGGER trigger_del_cluster_relation AFTER DELETE ON face FOR EACH ROW  BEGIN  DELETE FROM cluster_relation where  face_id = old.face_id; END;
CREATE TRIGGER trigger_del_cv_result AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM asset_cv_result where  asset_id = old.asset_id; END;
CREATE TRIGGER trigger_del_face AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM face where  asset_id = old.asset_id; END;
CREATE TRIGGER trigger_del_moment_relation AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM moment_relation where  asset_id = old.asset_id; END;
CREATE TRIGGER trigger_del_relation AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM asset_relation where  asset_id = old.asset_id; END;
CREATE TRIGGER trigger_del_scan AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM asset_scan where  asset_id = old.asset_id; END;
CREATE TRIGGER trigger_del_similarity AFTER DELETE ON asset FOR EACH ROW  BEGIN  DELETE FROM similarity_relation where  asset_id = old.asset_id; END;
CREATE VIEW view_moment_data AS    SELECT asset.asset_id, asset.media_type, asset.create_time_ms, asset.duration_ms, result.score, result.vida_score, result.big_leader, result.porn, location.city_id as city_id, l_info.name as city_name, result.similar_feature    FROM asset asset    JOIN asset_cv_result result ON asset.asset_id = result.asset_id and result.frame <=0    LEFT JOIN asset_location location on result.asset_id = location.asset_id    LEFT JOIN location l_info on location.city_id = l_info.id and l_info.type = 40 and result.frame <=0;

